1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO claim-office", () => {
5	  // Quote — base premiums and processing fee
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("quote for a single plain sword (steel, ench 3, not cursed, 0 years, first contract) yields 100 + 10 first-insurance + 5 fee = 115 G");
14	  it.todo("quote for a single plain amulet (silver, ench 2, not cursed, 0 years, first contract) yields 60 + 6 + 5 = 71 G (rounded up to 72? — check rounding)");
15	  it.todo("quote for a plain staff yields 80 G base premium component");
16	  it.todo("quote for a plain potion yields 40 G base premium component");
17	
18	  // Components
19	  it.todo("quote for 2 runes yields 50 G base premium (no block)");
20	  it.todo("quote for 3 runes yields 60 G base premium (block applies)");
21	  it.todo("quote for 4 runes yields 100 G base premium (no block — block requires exactly 3)");
22	  it.todo("quote for 7 runes yields 175 G base premium (3 + 4 = block of 3 plus 4 singles? actually 7×25 = 175)");
23	  it.todo("quote for 2 runes + 1 moonstone yields 75 G base premium (no block: different types)");
24	  it.todo("quote for 3 runes + 3 moonstones yields 120 G base premium (two separate blocks)");
25	
26	  // Item-specific modifiers
27	  it.todo("cursed sword adds 50% surcharge to its base premium");
28	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
29	  it.todo("sword with enchantment 4 does not add high-enchantment surcharge");
30	  it.todo("cursed sword with enchantment 5 adds both surcharges");
31	
32	  // Policy-wide modifiers
33	  it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base");
34	  it.todo("first item in a quote receives 10% first-insurance surcharge per item");
35	  it.todo("second and later contracts in a scenario receive a 15% follow-up-contract discount on policy base");
36	
37	  // Integration: newcomer with cursed sword example
38	  it.todo("newcomer (0 years) with cursed sword (steel ench 3) → premium 165 G");
39	  it.todo("long-standing customer's 2nd contract: cursed sword (ench 7), 3 years → premium 160 G");
40	
41	  // Multi-item modifier scope
42	  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to sword base; loyalty/first/follow-up apply to policy base");
43	
44	  // Rounding
45	  it.todo("premium rounded up (in MHPCO favor): 197.5 → 198");
46	  it.todo("payout rounded down (in MHPCO favor): 350.5 → 350");
47	
48	  // Claim — basic payout
49	  it.todo("regular sword (steel, ench 3) damage 500 → payout 400 (deductible 100)");
50	  it.todo("damage to a rune (insurance 250) damage 200 → payout 100 (deductible 100)");
51	
52	  // Claim — special clauses
53	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon: full, minus deductible)");
54	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-ench: 50% then deductible)");
55	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% rule wins over dragon)");
56	  it.todo("dragon sword, ench exactly 8, damage 1000 → payout 400 (high-ench clause applies at 8)");
57	
58	  // Claim — deductible per damage event
59	  it.todo("dragon attack damages sword(500) and amulet(300) → payout 600 (100 deductible per item)");
60	
61	  // Claim — multiple items same type
62	  it.todo("policy covers two swords; damage to both → each is separate damage with own deductible");
63	  it.todo("damages contains more entries of a type than insured → CLI exits non-zero, claim rejected");
64	
65	  // Cap
66	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
67	  it.todo("cursed sword: cap 2000 G (based on unmodified insurance value)");
68	  it.todo("sword + 3 runes (block): insurance sum 1750 G; block discount does not reduce cap");
69	  it.todo("two successive claims of 1500 G against sword (cap 2000): first 1400, then 600, remainingCap 0");
70	
71	  // Validation / errors
72	  it.todo("quote with unknown item type exits non-zero with stderr message; no results");
73	  it.todo("claim references item not in policy → exits non-zero with stderr");
74	  it.todo("claim contains damage with negative amount → exits non-zero with stderr");
75	
76	  // CLI integration
77	  it.todo("CLI reads scenario JSON from stdin and writes {results: [...]} to stdout");
78	});
